Here's the full pattern:

**XAML — wrap CollectionView in RefreshView for pull-to-refresh:**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel (using CommunityToolkit.Mvvm):**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _service;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IItemService service, INavigationService nav)
    {
        _service = service;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        var data = await _service.GetItemsAsync();
        MainThread.BeginInvokeOnMainThread(() =>
        {
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        });
        IsRefreshing = false;   // stops the spinner
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync($"detail?id={SelectedItem.Id}");
        SelectedItem = null;    // reset so user can re-select
    }
}
```

**Key bindings explained:**

| XAML Property | ViewModel Property | Why |
|---|---|---|
| `IsRefreshing` | `bool IsRefreshing` | Controls spinner; set `false` when done |
| `Command` (RefreshView) | `RefreshCommand` | Fires on pull-down gesture |
| `SelectedItem` | `Item? SelectedItem` | Two-way so you can null it after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires when selection changes — triggers nav |
| `ItemsSource` | `ObservableCollection<Item>` | Auto-updates UI on add/remove |

**Important details:**
- Use `ObservableCollection<T>`, never `List<T>` — otherwise the UI won't update.
- Set `x:DataType` on `DataTemplate` for compiled bindings.
- Reset `SelectedItem = null` after navigating so the same item can be tapped again.
- Set `IsRefreshing = false` at the end of your refresh logic to dismiss the spinner.
- Update collections on the **UI thread** via `MainThread.BeginInvokeOnMainThread`.
